1	import React from 'react';
2	import { cn } from '@/lib/utils';
3	import { CheckCircle, XCircle } from 'lucide-react';
4	
5	export interface ComparisonColumn {
6	  key: string;
7	  header: string;
8	  featured?: boolean;
9	}
10	
11	export interface ComparisonRow {
12	  feature: string;
13	  values: Record<string, React.ReactNode>;
14	  highlight?: string;
15	}
16	
17	interface ComparisonTableProps {
18	  columns: ComparisonColumn[];
19	  rows: ComparisonRow[];
20	  className?: string;
21	}
22	
23	const ComparisonTable: React.FC<ComparisonTableProps> = ({
24	  columns,
25	  rows,
26	  className,
27	}) => {
28	  return (
29	    <div className={cn('rounded-xl overflow-hidden border border-[var(--border)]', className)}>
30	      <table className="w-full border-collapse">
31	        <thead>
32	          <tr className="bg-[var(--primary)] text-white">
33	            <th className="text-left px-5 py-3.5 text-body-sm font-semibold whitespace-nowrap">
34	              Feature
35	            </th>
36	            {columns.map((col) => (
37	              <th
38	                key={col.key}
39	                className={cn(
40	                  'text-left px-5 py-3.5 text-body-sm font-semibold whitespace-nowrap',
41	                  col.featured && 'bg-[var(--primary-dark)]'
42	                )}
43	              >
44	                {col.header}
45	              </th>
46	            ))}
47	          </tr>
48	        </thead>
49	        <tbody>
50	          {rows.map((row, rowIndex) => (
51	            <tr
52	              key={row.feature}
53	              className={cn(
54	                'transition-colors duration-200 hover:bg-[var(--bg-accent)]',
55	                rowIndex % 2 === 0 ? 'bg-[var(--bg-primary)]' : 'bg-[var(--bg-secondary)]'
56	              )}
57	            >
58	              <td className="px-5 py-3 text-body-sm font-semibold text-[var(--text-primary)] border-r border-[var(--border)]">
59	                {row.feature}
60	              </td>
61	              {columns.map((col) => {
62	                const value = row.values[col.key];
63	                const isHighlighted = row.highlight === col.key;
64	                return (
65	                  <td
66	                    key={col.key}
67	                    className={cn(
68	                      'px-5 py-3 text-body-sm text-[var(--text-primary)] border-r border-[var(--border)] last:border-r-0',
69	                      col.featured && 'border-l-[3px] border-l-[var(--primary)]',
70	                      isHighlighted && 'font-bold text-[var(--accent)]'
71	                    )}
72	                  >
73	                    {value === true ? (
74	                      <CheckCircle
75	                        className="w-5 h-5 text-[var(--success)]"
76	                        strokeWidth={2}
77	                      />
78	                    ) : value === false ? (
79	                      <XCircle
80	                        className="w-5 h-5 text-[var(--text-light)]"
81	                        strokeWidth={2}
82	                      />
83	                    ) : (
84	                      value
85	                    )}
86	                  </td>
87	                );
88	              })}
89	            </tr>
90	          ))}
91	        </tbody>
92	      </table>
93	    </div>
94	  );
95	};
96	
97	export default ComparisonTable;
